class ResizableCanvas(FigureCanvas):
    def _sync_figure_to_canvas(self):
        fig = self.figure
        if fig is None:
            return

        dpi = fig.dpi
        scale = self.devicePixelRatioF() or 1.0
        w = max(self.width(), 1) * scale
        h = max(self.height(), 1) * scale

        fig.set_size_inches(w / dpi, h / dpi, forward=False)
        self.draw_idle()

    def resizeEvent(self, event):
        super().resizeEvent(event)
        self._sync_figure_to_canvas()


