    def bindButtons(self):
        self.load_data.clicked.connect(self.loadData)
        self.export_data.clicked.connect(self.exportData)

    def loadData(self):
        print("Loading Data")
        filepath, _ = QtWidgets.QFileDialog.getOpenFileName(
            self.centralwidget,
            "Select .npy data file",
            "",
            "NumPy files (*.npy)"
        )

        if not filepath:
            return

        filename = os.path.basename(filepath)
        patient_num = filename.split("_")[0]
        path = os.path.dirname(filepath)

        results = []
        print("Processing segment: ", 0)
        metrics, fig1, fig2 = process_segment_with_figure(path, patient_num, 0)
        results.append(metrics)

        for i in range(1, 30):
            print("Processing segment: ", i)
            metrics = process_segment(path, patient_num, i)
            results.append(metrics)

        if results:
            print("Calculating Values")
            mean_ecg_hr = round(np.mean([res['ecg_hr'] for res in results]))
            mean_ppg_hr = round(np.mean([res['ppg_hr'] for res in results]))
            mean_ecg_sqi = round(np.mean([res['ecg_sqi'] for res in results]),2)
            mean_ppg_sqi = round(np.mean([res['ppg_sqi'] for res in results]),2)
            mean_w_ecg = round(np.mean([res['ecg_weight'] for res in results]),2)
            mean_w_ppg = round(np.mean([res['ppg_weight'] for res in results]),2)
            mean_fused_hr = round(np.mean([res['fused_hr'] for res in results]))
            mean_fused_sdnn = round(np.mean([res['fused_sdnn'] for res in results]),2)
            mean_fused_rmssd = round(np.mean([res['fused_rmssd'] for res in results]),2)
        else:
            print("No results found")
            mean_ecg_hr = "XX"
            mean_ppg_hr = "XX"
            mean_ecg_sqi = "XX"
            mean_ppg_sqi = "XX"
            mean_w_ecg = "XX"
            mean_w_ppg = "XX"
            mean_fused_hr = "XX"
            mean_fused_sdnn = "XX"
            mean_fused_rmssd = "XX"

        self.ecg_heartrate_value.setText(str(mean_ecg_hr))
        self.ecg_sqi_value.setText(str(mean_ecg_sqi))
        self.ecg_weight_value.setText(str(mean_w_ecg))
        self.ppg_heartrate_value.setText(str(mean_ppg_hr))
        self.ppg_sqi_value.setText(str(mean_ppg_sqi))
        self.ppg_weight_value.setText(str(mean_w_ppg))
        self.fhr_value.setText(str(mean_fused_hr))
        self.fhrvsdnn_value.setText(str(mean_fused_sdnn))
        self.fhrvrmssd_value.setText(str(mean_fused_rmssd))

        self.plot(self.canvas1, fig1)
        self.plot(self.canvas2, fig2)
        self.canvas1.show()
        self.canvas2.show()

    def exportData(self):
        print("Exporting Data")

    def plot(self, canvas, fig):
        canvas.figure = fig
        fig.set_canvas(canvas)

        # Force the same resize behavior as manually resizing the window.
        event = QtGui.QResizeEvent(canvas.size(), canvas.size())
        canvas.resizeEvent(event)

        canvas.draw_idle()